Below is a simple Vue.js front-end implementation to interact with your `LoanNFT` smart contract. This code assumes that you have set up a Vue.js project and integrated it with the necessary dependencies, such as web3.js.

First, create a new Vue component called `LoanNFTApp.vue` and paste this code inside:

```html
<template>
  <div>
    <h1>Loan NFT Application</h1>
    <h2>Issue Loan</h2>
    <form @submit.prevent="onIssueLoan">
      <label for="borrower">Borrower Address:</label>
      <input type="text" id="borrower" v-model="loanForm.borrower" />
      <label for="principal">Principal:</label>
      <input type="number" id="principal" v-model="loanForm.principal" />
      <label for="interestRate">Interest Rate:</label>
      <input type="number" id="interestRate" v-model="loanForm.interestRate" />
      <label for="term">Term:</label>
      <input type="number" id="term" v-model="loanForm.term" />
      <label for="maturityDate">Maturity Date:</label>
      <input type="number" id="maturityDate" v-model="loanForm.maturityDate" />
      <button type="submit">Issue Loan</button>
    </form>
    <p>{{issueLoanStatus}}</p>
  </div>
</template>

<script>
import Web3 from "web3";
import LoanNFTJson from "@/abis/LoanNFT.json";

export default {
  data() {
    return {
      web3: null,
      contract: null,
      account: null,
      loanForm: {
        borrower: "",
        principal: 0,
        interestRate: 0,
        term: 0,
        maturityDate: 0
      },
      issueLoanStatus: ""
    };
  },
  async mounted() {
    // Connect to Metamask
    if (window.ethereum) {
      window.web3 = new Web3(window.ethereum);
      this.web3 = window.web3;
      await window.ethereum.enable();
    } else {
      alert("Please install Metamask to use this app");
      return;
    }

    // Get user account
    const accounts = await this.web3.eth.getAccounts();
    this.account = accounts[0];

    // Load and create an instance of the smart contract
    const networkId = await this.web3.eth.net.getId();
    const networkData = LoanNFTJson.networks[networkId];

    if (!networkData) {
      alert("Smart contract is not deployed to the detected network");
      return;
    }

    const contractAddress = networkData.address;
    this.contract = new this.web3.eth.Contract(LoanNFTJson.abi, contractAddress);
  },
  methods: {
    async onIssueLoan() {
      try {
        this.issueLoanStatus = "Submitting transaction...";
        await this.contract.methods
          .issueLoan(
            this.loanForm.borrower,
            this.loanForm.principal,
            this.loanForm.interestRate,
            this.loanForm.term,
            this.loanForm.maturityDate
          )
          .send({ from: this.account });

        this.issueLoanStatus = "Loan issued successfully";
      } catch (error) {
        console.error(error);
        this.issueLoanStatus = "Transaction failed!";
      }
    }
  }
};
</script>
```

